import java.io.BufferedReader;
import java.io.BufferedWriter;
import java.io.FileReader;
import java.io.FileWriter;
import java.io.IOException;
import java.io.Reader;
import java.util.ArrayList;
import java.util.StringTokenizer;

public class Magazin {
	private static int n;
	private static ArrayList<Integer>[] adj;
	private static int[] visited;
	private static int index = 0;
	private static int[] order;
	private static ArrayList<Pair> questions = new ArrayList<>();

	@SuppressWarnings("unchecked") 
	public static void main(final String[] args) throws IOException {
		var scanner = new MyScanner(new FileReader("magazin.in"));

		n = scanner.nextInt();
		adj = new ArrayList[n + 1];
		visited = new int[n + 1];
		order = new int[n];
		var q = scanner.nextInt();
		int i;
		for (i = 1; i <= n; i++) {
			adj[i] = new ArrayList<>();
		}
		for (i = 2; i <= n; i++) {
			var from = scanner.nextInt();
			adj[from].add(i);
		}

		for (i = 0; i < q; i++) {
			var from = scanner.nextInt();
			var howMany = scanner.nextInt();
			questions.add(new Pair(from, howMany));
		}
		try (var writer = new BufferedWriter(new FileWriter("magazin.out"));) {
			ArrayList<Integer> sol = solveTask();
			for (i = 0; i < sol.size(); i++) {
				writer.write(sol.get(i) + "\n");
			}
		}
	}

	static ArrayList<Integer> solveTask() {
		ArrayList<Integer> sol = new ArrayList<>();
		dfsRecursive(1);
		int[] max_after = new int[n + 1];
		int[] pos = new int[n + 1];

		//determinarea numarului de noduri din subarborele fiecarui nod
		int howMany = 0;
		for (int i = n - 1; i >= 0; i--) {
			howMany = 0;
			if (adj[order[i]].size() != 0) {
				howMany = 0;
				for (int neighbour : adj[order[i]]) {
					howMany += max_after[neighbour];
				}
			}
			max_after[order[i]] = adj[order[i]].size() + howMany;
		}
		//determinarea pozitiei fiecarui nod in parcurgerea in adancime
		for (int i = 0; i < n; i++) {
			pos[order[i]] = i;
		}
		//determinarea solutiei
		for (Pair question : questions) {
			//daca nu exista suficiente noduri in subarborele nodului solutia e -1
			if (question.howMany > max_after[order[pos[question.from]]]) {
				sol.add(-1);
			} else {
				sol.add(order[pos[question.from] + question.howMany]);
			}
		}
		return sol;
	}

	static void dfsRecursive(int node) {
		visited[node] = 1; 
		order[index++] = node;
		for (int neighbour : adj[node]) {
			if (visited[neighbour] == 0) {
				dfsRecursive(neighbour);
			}
		}
	}

	private static class Pair {
		int from;
		int howMany;

		Pair(int from, int howMany) {
			this.from = from;
			this.howMany = howMany;
		}
	}

	private static class MyScanner {
		private BufferedReader br;
		private StringTokenizer st;

		public MyScanner(Reader reader) {
			br = new BufferedReader(reader);
		}

		public String next() {
			while (st == null || !st.hasMoreElements()) {
				try {
					st = new StringTokenizer(br.readLine());
				} catch (IOException e) {
					e.printStackTrace();
				}
			}
			return st.nextToken();
		}

		public int nextInt() {
			return Integer.parseInt(next());
		}
	}
}

#include <bits/stdc++.h>
#include <iostream>
#include <fstream>

using namespace std;

/* 
 * se parcurge arborele recursiv RSD si se calculeaza pentru fieare nod
 * numarul de legaturi pe care le are sub el
 * si se retine ordinea de parcurgere a nodurilor in vectorul rsd
 */
int dfs_count(vector<int> adj[], int source, vector<int>& rsd, int *count) {
    rsd.push_back(source);
    for (int i = 0; i < (int)adj[source].size(); i++) {
        int aux = dfs_count(adj, adj[source][i], rsd, count);
        count[source] = count[source] + aux + 1;
    }
    return count[source];
}

int main() {
    FILE *fin = fopen("magazin.in", "rt");
    FILE *fout = fopen("magazin.out", "wt");

    int N, Q;
    fscanf(fin, "%d", &N);
    fscanf(fin, "%d", &Q);


    vector<int> adj[N + 1];
    int source;
    for (int i = 2; i <= N ; i++) {
        fscanf(fin, "%d", &source);
        adj[source].push_back(i);
    }
    /* ordine de parcurgere a nodurilor */
    vector<int> rsd;
    /* numarul de legaturi pe care nodul i le are sub el */
    int *count = (int*)calloc(N+1, sizeof(int));
    /* pozitia nodului i in vectorul rsd */
    int *index_map = (int*)calloc(N+1, sizeof(int));

    /*
     * se parcurge arborele si se calculeaza numarul de legaturi
     * pornind de la nodul 1
     */
    dfs_count(adj, 1, rsd, count);

    /* completare index_map */
    for (int i = 0; i <= N; i++) {
        index_map[rsd[i]] = i;
    }

    for (int i = 0; i < Q; i++) {
        /* citire date intrebare */
        int D, E;
        fscanf(fin, "%d", &D);
        fscanf(fin, "%d", &E);
        /* 
         * daca numarul de expedieri solicitat este mai mare decat
         * numarul de legaturi pe care le are nodul D, nu se poate
         * efectua expedierea, se afiseaza -1
         */
        if (E > count[D]) {
            fprintf(fout , "-1\n");
        /* altfel se afiseaza nodul in care se ajunge prin E expedieri */
        } else {
            fprintf(fout, "%d\n", rsd[index_map[D] + E]);
        }
    }

    return 0;
}
